package problems;
import java.util.*;

public class Largest3SameDigitNumberString {

    public static void main(String[] args) {
        String num = "2330300017779";
        System.out.println("Max: " + largestGoodInteger(num));
    }

    /**
     * Find largest 3-digit substring with all same digits.
     * 
     * Time: O(n), Space: O(1)
     * 
     * Approach 1: Sliding window - check each 3-char window
     * Approach 2: Iterate from "999" to "000" and check if exists
     */
    public static String largestGoodInteger(String num) {
        String maxGood = "";

        // Scan through string with sliding window of size 3
        for (int i = 0; i <= num.length() - 3; i++) {
            char c = num.charAt(i);

            // Check if next two chars are same as current
            if (num.charAt(i + 1) == c && num.charAt(i + 2) == c) {
                String good = num.substring(i, i + 3);

                // Update max if this is lexicographically larger
                if (maxGood.isEmpty() || good.compareTo(maxGood) > 0) {
                    maxGood = good;
                }
            }
        }

        return maxGood;
    }

    /**
     * Alternative approach: Check from largest to smallest
     * More efficient if we expect to find a large digit early
     */
    public static String largestGoodIntegerAlt(String num) {
        String[] numbers = {"999", "888", "777", "666", "555", 
                           "444", "333", "222", "111", "000"};

        for (String candidate : numbers) {
            if (num.contains(candidate)) {
                return candidate;
            }
        }

        return "";
    }
}

// Example 1:
// Input: num = "6777133339"
// Output: "777"
// Explanation: "777" and "333" are good integers, "777" is largest

// Example 2:
// Input: num = "2330300017779"
// Output: "777"
